"use client";

import {
  type ChangeEvent,
  type ComponentProps,
  type DragEvent as ReactDragEvent,
  type Ref,
  type RefObject,
  useEffect,
  useRef,
  useState,
} from "react";

import type { DropzoneValueChangeReason, DropzoneVisualState } from "../contracts";
import {
  compileDropzoneAccept,
  type DropzoneFileMetadata,
  type DropzoneFileRejection,
  type DropzonePolicy,
  type DropzoneProcessResult,
  getDropzoneDragVerdict,
  processDropzoneFiles,
  toDropzoneError,
} from "../lib/dropzone-validation";

export type DropzoneEvent = ReactDragEvent<HTMLElement> | ChangeEvent<HTMLInputElement>;
export type DropzoneGetFilesFromEvent = (event: DropzoneEvent, signal: AbortSignal) => readonly File[] | Promise<readonly File[]>;
export type DropzoneValueChangeDetails = {
  reason: DropzoneValueChangeReason;
  addedFiles: readonly File[];
  removedFiles: readonly File[];
};
export type DropzoneDropDetails = {
  acceptedFiles: readonly File[];
  fileRejections: readonly DropzoneFileRejection[];
  event: DropzoneEvent;
};
export type UseDropzoneOptions = {
  value?: readonly File[];
  defaultValue?: readonly File[];
  onValueChange?: (value: readonly File[], details: DropzoneValueChangeDetails) => void;
  policy?: DropzonePolicy;
  disabled?: boolean;
  drag?: boolean;
  preventDropOnDocument?: boolean;
  trackDocumentDrag?: boolean;
  getFilesFromEvent?: DropzoneGetFilesFromEvent;
  onDrop?: (details: DropzoneDropDetails) => void;
  onError?: (error: Error) => void;
};
export type UseDropzoneReturn = {
  value: readonly File[];
  fileRejections: readonly DropzoneFileRejection[];
  accept: string | undefined;
  multiple: boolean;
  disabled: boolean;
  dragEnabled: boolean;
  visualState: DropzoneVisualState;
  isDragActive: boolean;
  isDragAccept: boolean;
  isDragReject: boolean;
  isDragUnknown: boolean;
  isDragGlobal: boolean;
  isFileDialogActive: boolean;
  isProcessing: boolean;
  rootRef: RefObject<HTMLDivElement | null>;
  inputRef: RefObject<HTMLInputElement | null>;
  open: () => void;
  removeFile: (file: File) => void;
  clearFiles: () => void;
  clearRejections: () => void;
  reset: () => void;
  getRootProps: (props?: ComponentProps<"div">) => ComponentProps<"div">;
  getInputProps: (props?: ComponentProps<"input">) => ComponentProps<"input">;
};

type IntakeReason = Extract<DropzoneValueChangeReason, "drop" | "input">;
type ActiveDragState = Exclude<DropzoneVisualState, "idle" | "processing">;

const registeredDropzoneRoots = new WeakSet<EventTarget>();

export function useDropzone({
  value: controlledValue,
  defaultValue = [],
  onValueChange,
  policy,
  disabled = false,
  drag = true,
  preventDropOnDocument = true,
  trackDocumentDrag = false,
  getFilesFromEvent,
  onDrop,
  onError,
}: UseDropzoneOptions = {}): UseDropzoneReturn {
  const [uncontrolledValue, setUncontrolledValue] = useState<readonly File[]>(defaultValue);
  const [fileRejections, setFileRejections] = useState<readonly DropzoneFileRejection[]>([]);
  const [isDragActive, setIsDragActive] = useState(false);
  const [activeDragState, setActiveDragState] = useState<ActiveDragState>("unknown");
  const [isDragGlobal, setIsDragGlobal] = useState(false);
  const [isFileDialogActive, setIsFileDialogActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const rootRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const mountedInput = useRef<HTMLInputElement | null>(null);
  const localDragTargets = useRef(new Set<EventTarget>());
  const globalDragTargets = useRef(new Set<EventTarget>());
  const intakeController = useRef<AbortController | null>(null);
  const fallbackDialogCleanup = useRef<(() => void) | null>(null);
  const processingRef = useRef(false);
  const currentValue = controlledValue ?? uncontrolledValue;
  const currentValueRef = useRef(currentValue);
  const disabledRef = useRef(disabled);
  const dragEnabled = drag && !disabled;
  const dragEnabledRef = useRef(dragEnabled);
  const policyRef = useRef(policy);
  const customExtractionRef = useRef(Boolean(getFilesFromEvent));

  currentValueRef.current = currentValue;
  disabledRef.current = disabled;
  dragEnabledRef.current = dragEnabled;
  policyRef.current = policy;
  customExtractionRef.current = Boolean(getFilesFromEvent);

  const handleNativeCancelRef = useRef<(() => void) | null>(null);
  handleNativeCancelRef.current ??= () => {
    fallbackDialogCleanup.current?.();
    fallbackDialogCleanup.current = null;
    setIsFileDialogActive(false);
  };
  const handleNativeCancel = handleNativeCancelRef.current;

  function resetLocalDrag() {
    localDragTargets.current.clear();
    setIsDragActive(false);
    setActiveDragState("unknown");
  }

  function resetGlobalDrag() {
    globalDragTargets.current.clear();
    setIsDragGlobal(false);
  }

  function resetDragState() {
    resetLocalDrag();
    resetGlobalDrag();
  }

  function commitValue(nextValue: readonly File[], details: DropzoneValueChangeDetails) {
    if (areSameFiles(currentValueRef.current, nextValue)) return false;
    currentValueRef.current = nextValue;
    if (controlledValue === undefined) setUncontrolledValue(nextValue);
    onValueChange?.(nextValue, details);
    return true;
  }

  async function intake(event: DropzoneEvent, reason: IntakeReason) {
    intakeController.current?.abort();
    const controller = new AbortController();
    intakeController.current = controller;
    processingRef.current = true;
    setIsProcessing(true);

    let result: DropzoneProcessResult;
    try {
      const extractedFiles = await (getFilesFromEvent ?? defaultGetFilesFromEvent)(event, controller.signal);
      controller.signal.throwIfAborted();
      result = await processDropzoneFiles(extractedFiles, currentValueRef.current, policy, controller.signal);
    } catch (error) {
      if (controller.signal.aborted || intakeController.current !== controller) return;
      processingRef.current = false;
      setIsProcessing(false);
      onError?.(toDropzoneError(error));
      return;
    }

    if (controller.signal.aborted || intakeController.current !== controller) return;
    intakeController.current = null;
    processingRef.current = false;
    setIsProcessing(false);
    setFileRejections(result.fileRejections);
    commitValue(result.value, {
      reason,
      addedFiles: result.acceptedFiles,
      removedFiles: result.removedFiles,
    });
    onDrop?.({
      acceptedFiles: result.acceptedFiles,
      fileRejections: result.fileRejections,
      event,
    });
  }

  function open() {
    if (disabledRef.current || processingRef.current) return;
    const input = inputRef.current;
    if (!input) return;

    fallbackDialogCleanup.current?.();
    fallbackDialogCleanup.current = null;
    input.value = "";
    setIsFileDialogActive(true);

    if (input.oncancel === undefined) {
      const view = input.ownerDocument.defaultView;
      let timeout: ReturnType<typeof setTimeout> | undefined;
      const handleFocus = () => {
        timeout = setTimeout(() => setIsFileDialogActive(false), 300);
      };
      view?.addEventListener("focus", handleFocus, { once: true });
      fallbackDialogCleanup.current = () => {
        view?.removeEventListener("focus", handleFocus);
        clearTimeout(timeout);
      };
    }

    input.click();
  }

  function removeFile(file: File) {
    if (disabledRef.current || processingRef.current) return;
    const index = currentValueRef.current.indexOf(file);
    if (index < 0) return;
    const nextValue = currentValueRef.current.filter((_, fileIndex) => fileIndex !== index);
    commitValue(nextValue, { reason: "remove", addedFiles: [], removedFiles: [file] });
  }

  function clearFiles() {
    if (disabledRef.current || processingRef.current || currentValueRef.current.length === 0) return;
    const removedFiles = currentValueRef.current;
    commitValue([], { reason: "clear", addedFiles: [], removedFiles });
  }

  function clearRejections() {
    if (disabledRef.current || processingRef.current || fileRejections.length === 0) return;
    setFileRejections([]);
  }

  function reset() {
    if (disabledRef.current || processingRef.current) return;
    if (currentValueRef.current.length > 0) {
      const removedFiles = currentValueRef.current;
      commitValue([], { reason: "clear", addedFiles: [], removedFiles });
    }
    if (fileRejections.length > 0) setFileRejections([]);
  }

  function getRootProps(props: ComponentProps<"div"> = {}): ComponentProps<"div"> {
    const { onDragEnter, onDragOver, onDragLeave, onDragEnd, onDrop: callerOnDrop, ref, ...rootProps } = props;

    return {
      ...rootProps,
      ref: (node) => {
        if (rootRef.current !== node) {
          if (rootRef.current) registeredDropzoneRoots.delete(rootRef.current);
          rootRef.current = node;
          if (node) registeredDropzoneRoots.add(node);
        }
        assignRef(ref, node);
      },
      onDragEnter: (event) => {
        onDragEnter?.(event);
        if (!isFileDrag(event.dataTransfer)) return;
        event.stopPropagation();
        if (event.defaultPrevented || !dragEnabledRef.current) return;
        event.preventDefault();
        localDragTargets.current.add(event.target);
        setActiveDragState(
          getDropzoneDragVerdict(getDragMetadata(event.dataTransfer), currentValueRef.current, policyRef.current, {
            customExtraction: customExtractionRef.current,
          }),
        );
        setIsDragActive(true);
      },
      onDragOver: (event) => {
        onDragOver?.(event);
        if (!isFileDrag(event.dataTransfer)) return;
        event.stopPropagation();
        if (event.defaultPrevented || !dragEnabledRef.current) return;
        event.preventDefault();
        event.dataTransfer.dropEffect = "copy";
        if (!isDragActive) {
          setActiveDragState(
            getDropzoneDragVerdict(getDragMetadata(event.dataTransfer), currentValueRef.current, policyRef.current, {
              customExtraction: customExtractionRef.current,
            }),
          );
          setIsDragActive(true);
        }
      },
      onDragLeave: (event) => {
        onDragLeave?.(event);
        if (!isFileDrag(event.dataTransfer)) return;
        event.stopPropagation();
        localDragTargets.current.delete(event.target);
        if (event.relatedTarget === null || localDragTargets.current.size === 0) resetLocalDrag();
      },
      onDragEnd: (event) => {
        onDragEnd?.(event);
        if (!isFileDrag(event.dataTransfer)) return;
        event.stopPropagation();
        resetDragState();
      },
      onDrop: (event) => {
        callerOnDrop?.(event);
        if (!isFileDrag(event.dataTransfer)) return;
        event.stopPropagation();
        resetDragState();
        if (event.defaultPrevented || !dragEnabledRef.current) return;
        event.preventDefault();
        void intake(event, "drop");
      },
    };
  }

  function getInputProps(props: ComponentProps<"input"> = {}): ComponentProps<"input"> {
    const { onChange, ref, ...inputProps } = props;
    return {
      ...inputProps,
      type: "file",
      accept: compileDropzoneAccept(policy?.accept),
      multiple: policy?.multiple ?? true,
      disabled,
      ref: (node) => {
        if (mountedInput.current !== node) {
          mountedInput.current?.removeEventListener("cancel", handleNativeCancel);
          mountedInput.current = node;
          node?.addEventListener("cancel", handleNativeCancel);
        }
        inputRef.current = node;
        assignRef(ref, node);
      },
      onChange: (event) => {
        onChange?.(event);
        fallbackDialogCleanup.current?.();
        fallbackDialogCleanup.current = null;
        setIsFileDialogActive(false);
        if (!event.defaultPrevented && !disabledRef.current) void intake(event, "input");
      },
    };
  }

  useEffect(() => {
    if (!disabled && drag) return;
    if (disabled) {
      intakeController.current?.abort();
      intakeController.current = null;
      processingRef.current = false;
      setIsProcessing(false);
      fallbackDialogCleanup.current?.();
      fallbackDialogCleanup.current = null;
      setIsFileDialogActive(false);
    }
    localDragTargets.current.clear();
    globalDragTargets.current.clear();
    setIsDragActive(false);
    setActiveDragState("unknown");
    setIsDragGlobal(false);
  }, [disabled, drag]);

  useEffect(() => {
    const ownerDocument = rootRef.current?.ownerDocument ?? document;
    const ownerWindow = ownerDocument.defaultView;

    function resetDocumentGlobalDrag() {
      globalDragTargets.current.clear();
      setIsDragGlobal(false);
    }

    function resetDocumentDragState() {
      localDragTargets.current.clear();
      globalDragTargets.current.clear();
      setIsDragActive(false);
      setActiveDragState("unknown");
      setIsDragGlobal(false);
    }

    function handleDocumentDragOver(event: DragEvent) {
      if (preventDropOnDocument && isFileDrag(event.dataTransfer)) event.preventDefault();
    }

    function handleDocumentDrop(event: DragEvent) {
      resetDocumentDragState();
      if (preventDropOnDocument && isFileDrag(event.dataTransfer)) event.preventDefault();
    }

    function handleGlobalDragEnter(event: DragEvent) {
      if (!trackDocumentDrag || !dragEnabledRef.current || !isFileDrag(event.dataTransfer)) return;
      const dragOwner = getRegisteredDropzoneRoot(event);
      if (dragOwner && dragOwner !== rootRef.current) {
        resetDocumentGlobalDrag();
        return;
      }
      globalDragTargets.current.add(event.target ?? ownerDocument);
      setIsDragGlobal(true);
    }

    function handleGlobalDragLeave(event: DragEvent) {
      if (!isFileDrag(event.dataTransfer)) return;
      globalDragTargets.current.delete(event.target ?? ownerDocument);
      if (event.relatedTarget === null || globalDragTargets.current.size === 0) {
        resetDocumentGlobalDrag();
      }
    }

    function handleTerminalDrag() {
      resetDocumentDragState();
    }

    ownerDocument.addEventListener("dragover", handleDocumentDragOver);
    ownerDocument.addEventListener("drop", handleDocumentDrop);
    ownerDocument.addEventListener("dragenter", handleGlobalDragEnter, true);
    ownerDocument.addEventListener("dragleave", handleGlobalDragLeave, true);
    ownerDocument.addEventListener("drop", handleTerminalDrag, true);
    ownerDocument.addEventListener("dragend", handleTerminalDrag, true);
    ownerWindow?.addEventListener("blur", handleTerminalDrag);

    return () => {
      ownerDocument.removeEventListener("dragover", handleDocumentDragOver);
      ownerDocument.removeEventListener("drop", handleDocumentDrop);
      ownerDocument.removeEventListener("dragenter", handleGlobalDragEnter, true);
      ownerDocument.removeEventListener("dragleave", handleGlobalDragLeave, true);
      ownerDocument.removeEventListener("drop", handleTerminalDrag, true);
      ownerDocument.removeEventListener("dragend", handleTerminalDrag, true);
      ownerWindow?.removeEventListener("blur", handleTerminalDrag);
    };
  }, [preventDropOnDocument, trackDocumentDrag]);

  useEffect(
    () => () => {
      intakeController.current?.abort();
      if (rootRef.current) registeredDropzoneRoots.delete(rootRef.current);
      mountedInput.current?.removeEventListener("cancel", handleNativeCancel);
      fallbackDialogCleanup.current?.();
    },
    [handleNativeCancel],
  );

  let visualState: DropzoneVisualState = "idle";
  if (isProcessing) visualState = "processing";
  else if (isDragActive) visualState = activeDragState;
  else if (isDragGlobal) visualState = "unknown";

  return {
    value: currentValue,
    fileRejections,
    accept: compileDropzoneAccept(policy?.accept),
    multiple: policy?.multiple ?? true,
    disabled,
    dragEnabled,
    visualState,
    isDragActive,
    isDragAccept: visualState === "accept",
    isDragReject: visualState === "reject",
    isDragUnknown: visualState === "unknown",
    isDragGlobal,
    isFileDialogActive,
    isProcessing,
    rootRef,
    inputRef,
    open,
    removeFile,
    clearFiles,
    clearRejections,
    reset,
    getRootProps,
    getInputProps,
  };
}

export function defaultGetFilesFromEvent(event: DropzoneEvent): readonly File[] {
  return "dataTransfer" in event ? Array.from(event.dataTransfer.files) : Array.from(event.currentTarget.files ?? []);
}

function isFileDrag(dataTransfer: DataTransfer | null) {
  return dataTransfer ? Array.from(dataTransfer.types).includes("Files") : false;
}

function getRegisteredDropzoneRoot(event: DragEvent) {
  for (const target of event.composedPath()) {
    if (target && registeredDropzoneRoots.has(target)) return target;
  }
  return undefined;
}

function getDragMetadata(dataTransfer: DataTransfer): readonly DropzoneFileMetadata[] | null {
  const files = Array.from(dataTransfer.files);
  if (files.length > 0) return files;

  const fileItems = Array.from(dataTransfer.items).filter((item) => item.kind === "file");
  if (fileItems.length === 0) return null;
  return fileItems.map((item) => item.getAsFile() ?? { type: item.type || undefined });
}

function areSameFiles(left: readonly File[], right: readonly File[]) {
  return left.length === right.length && left.every((file, index) => file === right[index]);
}

function assignRef<Element>(ref: Ref<Element> | undefined, value: Element | null) {
  if (typeof ref === "function") ref(value);
  else if (ref) ref.current = value;
}

import type { DropzoneSelectionMode, DropzoneVisualState } from "../contracts";

export const DropzoneErrorCode = {
  FileInvalidType: "file-invalid-type",
  FileTooLarge: "file-too-large",
  FileTooSmall: "file-too-small",
  TooManyFiles: "too-many-files",
  FileAlreadySelected: "file-already-selected",
} as const;

export type DropzoneErrorCodeValue = (typeof DropzoneErrorCode)[keyof typeof DropzoneErrorCode];
export type DropzoneAccept = Readonly<Record<string, readonly string[]>>;
export type DropzoneFileError = { code: DropzoneErrorCodeValue | string; message: string };
export type DropzoneFileRejection = { file: File; errors: readonly DropzoneFileError[] };
export type DropzoneValidatorResult = DropzoneFileError | readonly DropzoneFileError[] | null;
export type DropzoneValidator = (
  file: File,
  signal: AbortSignal,
) => DropzoneValidatorResult | Promise<DropzoneValidatorResult>;
export type DropzonePolicy = {
  accept?: DropzoneAccept;
  minSize?: number;
  maxSize?: number;
  maxFiles?: number;
  multiple?: boolean;
  selectionMode?: DropzoneSelectionMode;
  allowDuplicates?: boolean;
  validator?: DropzoneValidator;
};

export type DropzoneFileMetadata = {
  name?: string;
  size?: number;
  type?: string;
  lastModified?: number;
  webkitRelativePath?: string;
};

export type DropzoneProcessResult = {
  acceptedFiles: readonly File[];
  fileRejections: readonly DropzoneFileRejection[];
  value: readonly File[];
  removedFiles: readonly File[];
};

export type DropzoneDragVerdictOptions = {
  customExtraction?: boolean;
};

type NormalizedAcceptEntry = {
  mime: string;
  extensions: readonly string[];
};

type FileAcceptance = "accept" | "reject" | "unknown";

const DEFAULT_POLICY = {
  minSize: 0,
  maxSize: Number.POSITIVE_INFINITY,
  maxFiles: 0,
  multiple: true,
  selectionMode: "append",
  allowDuplicates: false,
} satisfies Required<Pick<DropzonePolicy, "minSize" | "maxSize" | "maxFiles" | "multiple" | "selectionMode" | "allowDuplicates">>;

export function normalizeDropzoneAccept(accept: DropzoneAccept | undefined): readonly NormalizedAcceptEntry[] {
  if (!accept) return [];

  return Object.entries(accept).flatMap(([rawMime, rawExtensions]) => {
    const mime = rawMime.trim().toLowerCase();
    const extensions = Array.from(
      new Set(
        rawExtensions.flatMap((rawExtension) => {
          const extension = rawExtension.trim().toLowerCase();
          if (!extension) return [];
          return [extension.startsWith(".") ? extension : `.${extension}`];
        }),
      ),
    );

    return mime || extensions.length > 0 ? [{ mime, extensions }] : [];
  });
}

export function compileDropzoneAccept(accept: DropzoneAccept | undefined): string | undefined {
  const values = normalizeDropzoneAccept(accept).flatMap(({ mime, extensions }) => {
    if (extensions.length > 0) return extensions;
    return mime ? [mime] : [];
  });
  return values.length > 0 ? values.join(",") : undefined;
}

export function isDropzoneFileAccepted(file: Pick<File, "name" | "type">, accept: DropzoneAccept | undefined) {
  return getFileAcceptance(file, normalizeDropzoneAccept(accept)) === "accept";
}

export function normalizeDropzoneMaxFiles(maxFiles: number | undefined) {
  const value = maxFiles ?? DEFAULT_POLICY.maxFiles;
  if (!Number.isFinite(value) || value <= 0) return Number.POSITIVE_INFINITY;
  return Math.max(1, Math.floor(value));
}

export function getDropzoneSelectionMode(policy: DropzonePolicy | undefined): DropzoneSelectionMode {
  return policy?.multiple === false ? "replace" : (policy?.selectionMode ?? DEFAULT_POLICY.selectionMode);
}

export function getDropzoneCapacity(policy: DropzonePolicy | undefined) {
  return policy?.multiple === false ? 1 : normalizeDropzoneMaxFiles(policy?.maxFiles);
}

export function getDropzoneFileIdentity(file: DropzoneFileMetadata) {
  const path = file.webkitRelativePath || file.name || "";
  return `${path}\0${file.size ?? ""}\0${file.type?.toLowerCase() ?? ""}\0${file.lastModified ?? ""}`;
}

export function toDropzoneError(value: unknown) {
  return value instanceof Error ? value : new Error(String(value));
}

export async function validateDropzoneFile(
  file: File,
  policy: DropzonePolicy | undefined,
  signal: AbortSignal,
): Promise<readonly DropzoneFileError[]> {
  const errors: DropzoneFileError[] = [];
  const minSize = policy?.minSize ?? DEFAULT_POLICY.minSize;
  const maxSize = policy?.maxSize ?? DEFAULT_POLICY.maxSize;

  if (!isDropzoneFileAccepted(file, policy?.accept)) {
    errors.push({
      code: DropzoneErrorCode.FileInvalidType,
      message: "File type is not accepted.",
    });
  }
  if (file.size < minSize) {
    errors.push({
      code: DropzoneErrorCode.FileTooSmall,
      message: `File is smaller than the ${formatDropzoneFileSize(minSize)} minimum.`,
    });
  }
  if (file.size > maxSize) {
    errors.push({
      code: DropzoneErrorCode.FileTooLarge,
      message: `File is larger than the ${formatDropzoneFileSize(maxSize)} limit.`,
    });
  }

  if (policy?.validator) {
    signal.throwIfAborted();
    const result = await policy.validator(file, signal);
    signal.throwIfAborted();
    if (result) errors.push(...normalizeValidatorErrors(result));
  }

  return errors;
}

export async function processDropzoneFiles(
  files: readonly File[],
  currentValue: readonly File[],
  policy: DropzonePolicy | undefined,
  signal: AbortSignal,
): Promise<DropzoneProcessResult> {
  signal.throwIfAborted();
  const validatedFiles = await Promise.all(
    files.map(async (file) => ({ file, errors: await validateDropzoneFile(file, policy, signal) })),
  );
  signal.throwIfAborted();

  const acceptedFiles: File[] = [];
  const fileRejections: DropzoneFileRejection[] = [];
  const selectionMode = getDropzoneSelectionMode(policy);
  const capacity = getDropzoneCapacity(policy);
  const selectedFiles = selectionMode === "append" ? [...currentValue] : [];
  const selectedIdentities = new Set(
    policy?.allowDuplicates
      ? []
      : (selectionMode === "append" ? currentValue : []).map(getDropzoneFileIdentity),
  );

  for (const { file, errors } of validatedFiles) {
    if (errors.length > 0) {
      fileRejections.push({ file, errors });
      continue;
    }

    const identity = getDropzoneFileIdentity(file);
    if (!policy?.allowDuplicates && selectedIdentities.has(identity)) {
      fileRejections.push({
        file,
        errors: [
          {
            code: DropzoneErrorCode.FileAlreadySelected,
            message: `File "${file.name}" is already selected.`,
          },
        ],
      });
      continue;
    }

    if (selectedFiles.length >= capacity) {
      fileRejections.push({
        file,
        errors: [{ code: DropzoneErrorCode.TooManyFiles, message: "Too many files." }],
      });
      continue;
    }

    acceptedFiles.push(file);
    selectedFiles.push(file);
    selectedIdentities.add(identity);
  }

  if (selectionMode === "replace" && acceptedFiles.length === 0) {
    return {
      acceptedFiles,
      fileRejections,
      value: currentValue,
      removedFiles: [],
    };
  }

  return {
    acceptedFiles,
    fileRejections,
    value: selectedFiles,
    removedFiles: selectionMode === "replace" ? getRemovedFiles(currentValue, selectedFiles) : [],
  };
}

export function getDropzoneDragVerdict(
  files: readonly DropzoneFileMetadata[] | null,
  currentValue: readonly File[],
  policy: DropzonePolicy | undefined,
  options: DropzoneDragVerdictOptions = {},
): Exclude<DropzoneVisualState, "idle" | "processing"> {
  const selectionMode = getDropzoneSelectionMode(policy);
  const capacity = getDropzoneCapacity(policy);
  if (selectionMode === "append" && currentValue.length >= capacity) return "reject";
  if (!files || files.length === 0) return "unknown";

  const availableSlots = selectionMode === "append" ? capacity - currentValue.length : capacity;
  if (files.length > availableSlots) return "reject";

  const normalizedAccept = normalizeDropzoneAccept(policy?.accept);
  const metadataVerdicts = files.map((file) => getDropzoneMetadataVerdict(file, normalizedAccept, policy));
  if (metadataVerdicts.includes("reject")) return "reject";

  const duplicateVerdict = getDropzoneDuplicateVerdict(files, currentValue, policy, selectionMode);
  if (duplicateVerdict === "reject") return "reject";
  if (
    policy?.validator ||
    options.customExtraction ||
    metadataVerdicts.includes("unknown") ||
    duplicateVerdict === "unknown"
  ) {
    return "unknown";
  }
  return "accept";
}

export function formatDropzoneFileSize(size: number) {
  const safeSize = Number.isFinite(size) && size >= 0 ? size : 0;
  const units = ["B", "KB", "MB", "GB", "TB"];
  if (safeSize === 0) return "0 B";

  const unitIndex = Math.min(Math.floor(Math.log(safeSize) / Math.log(1024)), units.length - 1);
  const value = Math.round((safeSize / 1024 ** unitIndex) * 10) / 10;
  return `${value} ${units[unitIndex]}`;
}

function getFileAcceptance(
  file: Pick<DropzoneFileMetadata, "name" | "type">,
  entries: readonly NormalizedAcceptEntry[],
): FileAcceptance {
  if (entries.length === 0) return "accept";
  const verdicts = entries.map((entry) => getAcceptEntryVerdict(file, entry));
  if (verdicts.includes("accept")) return "accept";
  return verdicts.includes("unknown") ? "unknown" : "reject";
}

function getAcceptEntryVerdict(
  file: Pick<DropzoneFileMetadata, "name" | "type">,
  { mime, extensions }: NormalizedAcceptEntry,
): FileAcceptance {
  if (extensions.length > 0) {
    if (!file.name) return "unknown";
    const name = file.name.toLowerCase();
    return extensions.some((extension) => name.endsWith(extension)) ? "accept" : "reject";
  }

  if (!file.type) return "unknown";
  const type = file.type.toLowerCase();
  const matchesMime = mime.endsWith("/*") ? type.startsWith(mime.slice(0, -1)) : type === mime;
  return matchesMime ? "accept" : "reject";
}

function getDropzoneMetadataVerdict(
  file: DropzoneFileMetadata,
  normalizedAccept: readonly NormalizedAcceptEntry[],
  policy: DropzonePolicy | undefined,
): FileAcceptance {
  const acceptance = getFileAcceptance(file, normalizedAccept);
  if (acceptance === "reject") return "reject";
  if (file.size === undefined) return "unknown";
  if (file.size < (policy?.minSize ?? DEFAULT_POLICY.minSize)) return "reject";
  if (file.size > (policy?.maxSize ?? DEFAULT_POLICY.maxSize)) return "reject";
  return acceptance;
}

function getDropzoneDuplicateVerdict(
  files: readonly DropzoneFileMetadata[],
  currentValue: readonly File[],
  policy: DropzonePolicy | undefined,
  selectionMode: DropzoneSelectionMode,
): FileAcceptance {
  if (policy?.allowDuplicates) return "accept";

  const selectedIdentities = new Set(
    selectionMode === "append" ? currentValue.map(getDropzoneFileIdentity) : [],
  );
  let hasUnknownIdentity = false;
  for (const file of files) {
    if (!hasCompleteIdentity(file)) {
      hasUnknownIdentity = true;
      continue;
    }
    const identity = getDropzoneFileIdentity(file);
    if (selectedIdentities.has(identity)) return "reject";
    selectedIdentities.add(identity);
  }
  return hasUnknownIdentity ? "unknown" : "accept";
}

function isDropzoneErrorList(
  result: DropzoneFileError | readonly DropzoneFileError[],
): result is readonly DropzoneFileError[] {
  return Array.isArray(result);
}

function normalizeValidatorErrors(
  result: DropzoneFileError | readonly DropzoneFileError[],
): readonly DropzoneFileError[] {
  return isDropzoneErrorList(result) ? result : [result];
}

function hasCompleteIdentity(file: DropzoneFileMetadata) {
  return (
    Boolean(file.webkitRelativePath || file.name) &&
    file.size !== undefined &&
    file.type !== undefined &&
    file.lastModified !== undefined
  );
}

function getRemovedFiles(currentValue: readonly File[], nextValue: readonly File[]) {
  const unmatchedNext = [...nextValue];
  return currentValue.filter((file) => {
    const index = unmatchedNext.indexOf(file);
    if (index < 0) return true;
    unmatchedNext.splice(index, 1);
    return false;
  });
}

